using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "above", "below",
        "this", "that", "these", "those", "it", "its", "he", "she", "they",
        "we", "you", "i", "me", "him", "her", "us", "them", "my", "your",
        "his", "our", "their", "what", "which", "who", "whom", "when",
        "where", "why", "how", "not", "no", "nor", "do", "does", "did",
        "has", "have", "had", "be", "been", "being", "will", "would",
        "shall", "should", "may", "might", "must", "can", "could", "about",
        "if", "then", "so", "than", "too", "very", "just", "also", "each",
        "such", "more", "some", "any", "all", "both", "other", "over"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"[\w']+", RegexOptions.Compiled)]
    private static partial Regex WordTokenizer();

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        var topIndices = sentenceScores
            .Select((score, index) => (Score: score, Index: index))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .Select(x => x.Index)
            .OrderBy(i => i) // preserve original order
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));

        return (summary, sentences.Count, topIndices.Count);
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var match in WordTokenizer().EnumerateMatches(sentence))
            {
                var word = sentence.AsSpan(match.Index, match.Length).ToString();
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
                }
            }
        }

        // Normalize by maximum frequency
        if (frequencies.Count > 0)
        {
            var max = frequencies.Values.Max();
            foreach (var key in frequencies.Keys)
            {
                frequencies[key] /= max;
            }
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            double score = 0;
            foreach (var match in WordTokenizer().EnumerateMatches(sentence))
            {
                var word = sentence.AsSpan(match.Index, match.Length).ToString();
                score += wordFrequencies.GetValueOrDefault(word);
            }
            scores.Add(score);
        }

        return scores;
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summarizer.Summarize(
            request.DocumentText,
            request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

